import{_ as a,o as e,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/cv-math.png",c=JSON.parse('{"title":"CV Math","description":"","frontmatter":{},"headers":[],"relativePath":"modules/cv-math.md","filePath":"modules/cv-math.md"}'),n={name:"modules/cv-math.md"};function d(i,t,l,h,p,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="cv-math" tabindex="-1">CV Math <a class="header-anchor" href="#cv-math" aria-label="Permalink to &quot;CV Math&quot;">​</a></h1><p><strong>Category:</strong> Control</p><p>General-purpose CV math utility. Takes two inputs and applies a selectable operation. The most common use is Add mode: connect a pot/CC to input A and an LFO to input B, output = A + B. This lets you modulate around a manually-controlled center point.</p><img src="'+s+'" alt="cv-math module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inA</strong></td><td>First operand.</td></tr><tr><td><strong>inB</strong></td><td>Second operand.</td></tr><tr><td><strong>mode</strong></td><td>Operation select CV (0-1 sweeps through modes). Overrides mode param.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>out</strong></td><td>Result of the math operation.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Add mode: Pot (0-1) + LFO (bipolar, small depth) = modulation around pot setting. Multiply mode: use as a VCA for control signals (LFO * envelope = tremolo depth that follows dynamics). Min/Max: useful for limiting CV range.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const _=a(n,[["render",d]]);export{c as __pageData,_ as default};
